    const startISO = formatDateToISOWithTimeZone(startVal, '00', '00', '00', !!enableTimePicker);
    const endISO = formatDateToISOWithTimeZone(endVal, '00', '00', '00', !!enableTimePicker);
    const startDate = startISO ? new Date(startISO) : null;
    const endDate = endISO ? new Date(endISO) : null;
    const startInvalid = !startVal || !startDate || Number.isNaN(startDate.getTime());
    const endInvalid = !endVal || !endDate || Number.isNaN(endDate.getTime());
